async function loadSharedDashboardData() {
  try {
    const response = await fetch(`${SHARED_DATA_URL}?v=${APP_DATA_VERSION}&t=${Date.now()}`, { cache: 'no-store' });
    if (!response.ok) return false;

    const payload = await response.json();
    const rows = Array.isArray(payload) ? payload : payload.rows;
    if (!Array.isArray(rows) || !rows.length) return false;

    state.rows = rows;
    state.fileName = payload.fileName || 'GitHub shared raw data';
    state.forceLatestMonth = true;
    state.sharedDataLoaded = true;
    return true;
  } catch (err) {
    console.info('공유 데이터 파일을 불러오지 못했습니다. 브라우저 저장 데이터 또는 기본 데이터를 사용합니다.', err);
    return false;
  }
}

function downloadJsonFile(filename, data) {
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}

function downloadSharedDataJson() {
  if (!state.rows || !state.rows.length) {
    alert('내보낼 데이터가 없습니다.');
    return;
  }

  downloadJsonFile('fb_finance_dashboard_data.json', {
    schemaVersion: 1,
    appDataVersion: APP_DATA_VERSION,
    exportedAt: new Date().toISOString(),
    fileName: state.fileName || 'uploaded raw data',
    rows: state.rows
  });
}

const savedDashboardState = loadSavedDashboardState();
let state = savedDashboardState ? {
  rows: savedDashboardState.rows,
  fileName: savedDashboardState.fileName,
  forceLatestMonth: true,
  sharedDataLoaded: false
} : {
  rows: INITIAL_ROWS,
  fileName: DEFAULT_FILE_NAME,
  forceLatestMonth: true,
  sharedDataLoaded: false
};

let rawSortState = { key: 'date', direction: 'desc' };

const preferredBizBrand = [
  ['퍼니플러스', '퍼니츠'],
  ['에프비글로벌', '풀오브빈스'],
  ['에프비글로벌', '뽀뽀백번']
];

const preferredSalesChannels = [
  'Smartstore', 'Coupang', "Today's house", 'Cafe24', 'Re-think', 'Ssg', 'Kakao shopping', 'Pet fair', 'Petbazaar',
  '스마트스토어', '쿠팡', '오늘의집', '자사몰', '리씽크', '신세계', '카카오쇼핑', '펫박람회', '펫바자'
];

const preferredCogs = ['상품매출원가', '상품제조원가', '기초상품재고액', '당기상품매입액', '기말상품재고액'];
const preferredOpexCats = ['급여', '복리후생비', '여비교통비', '접대비', '통신비', '도서인쇄비', '세금과공과', '지급임차료', '건물관리비', '차량유지비', '운송비', '소모품비', '광고선전비', '지급수수료', '보험료', '잡비', '미분류'];
const preferredAdAccounts = ['Performance', 'SA', 'DA', 'META', 'SEO', 'Viral', 'VIRAL', 'Mass Media', '옥외광고', 'Tool cost', '마케팅(기타비용)', '촬영'];
const preferredFeeAccounts = ['플랫폼 수수료', '공구 수수료', '공구수수료', '외주비', '보관료', '수수료', '용역비'];
const taxAccounts = ['법인세', '지방소득세', '부가가치세'];

const $ = sel => document.querySelector(sel);
const text = v => (v ?? '').toString().trim();
const norm = v => text(v).replace(/\s+/g, '').toLowerCase();
const isBlank = v => text(v) === '';
const uniq = arr => [...new Set(arr.filter(v => !isBlank(v)))];

const salesChannelLabelMap = {
  'smartstore':'스마트스토어',
  '스마트스토어':'스마트스토어',
  'coupang':'쿠팡',
  '쿠팡':'쿠팡',
  "today'shouse":'오늘의집',
  'todayshouse':'오늘의집',
  '오늘의집':'오늘의집',
  'cafe24':'자사몰',
  '자사몰':'자사몰',
  're-think':'리씽크',
  'rethink':'리씽크',
  '리씽크':'리씽크',
  'ssg':'신세계',
  '신세계':'신세계',
  'kakaoshopping':'카카오쇼핑',
  '카카오쇼핑':'카카오쇼핑',
  'petfair':'펫박람회',
  '펫박람회':'펫박람회',
  'petbazaar':'펫바자',
  '펫바자':'펫바자'
};

function normalizeKey(v) {
  return text(v).replace(/[\s\-_'’]/g, '').toLowerCase();
}

function mapSalesChannelName(v) {
  const key = normalizeKey(v);
  return salesChannelLabelMap[key] || text(v);
}

function toNum(v) {
  if (typeof v === 'number' && isFinite(v)) return v;
  const s = text(v).replace(/,/g, '').replace(/원/g, '').replace(/\s/g, '');
  if (!s || s === '-') return 0;
  const n = Number(s);
  return isFinite(n) ? n : 0;
}

function excelSerialToDate(serial) {
  const n = Number(serial);
  if (!isFinite(n)) return null;
  const utc = Date.UTC(1899, 11, 30) + Math.round(n) * 86400000;
  return new Date(utc);
}

function parseAnyDate(v) {
  if (v instanceof Date && !isNaN(v)) return v;
  if (typeof v === 'number') return excelSerialToDate(v);
  const s = text(v);
  if (!s) return null;
  if (/^\d+(\.\d+)?$/.test(s)) return excelSerialToDate(Number(s));
  const cleaned = s.replace(/[.]/g, '-').replace(/\//g, '-');
  const d = new Date(cleaned);
  if (!isNaN(d)) return d;
  return null;
}

function monthOf(v) {
  const d = parseAnyDate(v);
  if (!d) return '';
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2, '0')}`;
}

function monthLabel(m) {
  if (!m) return '-';
  const [y, mo] = m.split('-');
  return `${y}년 ${mo}월`;
}

function fmt(n) {
  const v = Math.round(Number(n) || 0);
  if (Math.abs(v) < 1) return '-';
  return v.toLocaleString('ko-KR');
}

function fmtPct(n) {
  if (!isFinite(n)) return '-';
  return (n * 100).toFixed(1) + '%';
}

function categoryOf(row) {
  const c = text(row.category);
  const a = text(row.account);
  if (c.includes('매출원가') || a.includes('매출원가') || a.includes('상품제조원가')) return '매출원가';
  if (c === '매출' || c.includes('매출액') || a === '상품매출') return '매출';
  if (c.includes('영업외수익')) return '영업외수익';
  if (c.includes('영업외비용')) return '영업외비용';
  if (c.includes('소득세') || c.includes('법인세') || c.includes('부가가치세') || taxAccounts.some(x => a.includes(x))) return '소득세등';
  return c || '미분류';
}

function amountOf(row) {
  const cat = categoryOf(row);
  if (cat === '매출') return toNum(row.sales) || (toNum(row.payment) - toNum(row.refund));
  return toNum(row.cost);
}

function currentYear() {
  return $('#yearSelect') ? $('#yearSelect').value : '';
}

function currentMonthOnly() {
  return $('#monthSelect') ? $('#monthSelect').value : '';
}

function currentMonth() {
  const year = currentYear();
  const month = currentMonthOnly();
  if (!year) return '';
  if (!month || month === '__ALL__') return '';
  return `${year}-${month}`;
}

function currentBusiness() {
  return $('#businessSelect').value;
}

function currentBrand() {
  return $('#brandSelect') ? $('#brandSelect').value : '__ALL__';
}

function currentPeriodType() {
  return currentMonthOnly() === '__ALL__' ? 'yearly' : 'monthly';
}

function rowsByYear(year) {
  const biz = currentBusiness();
  const brand = currentBrand();
  return state.rows.filter(r =>
    year && r.month && r.month.startsWith(year + '-') &&
    (biz === '__ALL__' || effectiveBusiness(r) === biz) &&
    (brand === '__ALL__' || effectiveBrand(r) === brand)
  );
}

function availableYearsForCurrentFilter() {
  const biz = currentBusiness();
  const brand = currentBrand();
  return uniq(state.rows
    .filter(r =>
      r.month &&
      (biz === '__ALL__' || effectiveBusiness(r) === biz) &&
      (brand === '__ALL__' || effectiveBrand(r) === brand)
    )
    .map(r => r.month.split('-')[0]))
    .sort();
}

function monthRows() {
  const month = currentMonth();
  const biz = currentBusiness();
  const brand = currentBrand();
  return state.rows.filter(r =>
    r.month === month &&
    (biz === '__ALL__' || effectiveBusiness(r) === biz) &&
    (brand === '__ALL__' || effectiveBrand(r) === brand)
  );
}

function statementRows() {
  return currentPeriodType() === 'yearly' ? rowsByYear(currentYear()) : monthRows();
}

function statementLabel() {
  const year = currentYear();
  const month = currentMonthOnly();
  if (!year) return '-';
  if (month === '__ALL__') return `${year}년 통합`;
  return `${year}년 ${month}월`;
}

function rowsForColumn(rows, col) {
  if (!col) return rows;
  return rows.filter(r => effectiveBusiness(r) === col.business && effectiveBrand(r) === col.brand);
}

function sumBy(rows, col, predicate) {
  return rowsForColumn(rows, col).reduce((sum, r) => predicate(r) ? sum + amountOf(r) : sum, 0);
}

function salesTotal(rows, col) { return sumBy(rows, col, r => categoryOf(r) === '매출'); }
function cogsTotal(rows, col) { return sumBy(rows, col, r => categoryOf(r) === '매출원가'); }
function nonOpIncome(rows, col) { return sumBy(rows, col, r => categoryOf(r) === '영업외수익'); }
function nonOpExpense(rows, col) { return sumBy(rows, col, r => categoryOf(r) === '영업외비용'); }
function taxTotal(rows, col) { return sumBy(rows, col, r => categoryOf(r) === '소득세등'); }
function opexTotal(rows, col) {
  return sumBy(rows, col, r => !['매출', '매출원가', '영업외수익', '영업외비용', '소득세등'].includes(categoryOf(r)));
}

function metric(rows, col, key) {
  const sales = salesTotal(rows, col);
  const cogs = cogsTotal(rows, col);
  const gp = sales - cogs;
  const opex = opexTotal(rows, col);
  const op = gp - opex;
  const nonIncome = nonOpIncome(rows, col);
  const nonExpense = nonOpExpense(rows, col);
  const preTax = op + nonIncome - nonExpense;
  const tax = taxTotal(rows, col);
  const net = preTax - tax;
  return { sales, cogs, gp, opex, op, nonIncome, nonExpense, preTax, tax, net }[key] || 0;
}

function ordered(values, preferred) {
  const set = new Set(values);
  const first = preferred.filter(x => set.has(x));
  const rest = [...set].filter(x => !preferred.includes(x)).sort((a, b) => a.localeCompare(b, 'ko'));
  return [...first, ...rest];
}

function effectiveBusiness(row) {
  const brand = text(row.brand);
  if (brand === '퍼니츠') return '퍼니플러스';
  if (brand === '풀오브빈스' || brand === '뽀뽀백번') return '에프비글로벌';
  return text(row.business);
}

function effectiveBrand(row) {
  return text(row.brand);
}

function isJointPurchaseFee(row) {
  const account = text(row.account);
  const memo = text(row.memo);
  return account === '공구 수수료' || account === '공구수수료' || (account === '수수료' && memo.includes('공구'));
}

function isOutsourceFee(row) {
  const account = text(row.account);
  const memo = text(row.memo);
  return account === '외주비' || account === '용역비' || memo.includes('외주');
}

function isStorageFee(row) {
  return text(row.account) === '보관료';
}

function getColumns(rows) {
  const keySet = uniq(rows.map(r => `${effectiveBusiness(r)}__||__${effectiveBrand(r)}`));
  const pairs = keySet.map(k => {
    const [business, brand] = k.split('__||__');
    return { business, brand };
  });
  const preferred = preferredBizBrand
    .filter(([b, br]) => pairs.some(p => p.business === b && p.brand === br))
    .map(([business, brand]) => ({ business, brand }));
  const rest = pairs
    .filter(p => !preferred.some(x => x.business === p.business && x.brand === p.brand))
    .sort((a, b) => `${a.business}${a.brand}`.localeCompare(`${b.business}${b.brand}`, 'ko'));
  return [...preferred, ...rest];
}

function buildRows(rows) {
  const salesChannelsRaw = ordered(uniq(rows.filter(r => categoryOf(r) === '매출').map(r => r.memo)), preferredSalesChannels);
  const salesChannels = salesChannelsRaw.map(raw => [raw, mapSalesChannelName(raw)]);
  const cogsAccounts = ordered(uniq(rows.filter(r => categoryOf(r) === '매출원가').map(r => r.account)), preferredCogs);
  const opexCats = ordered(uniq(rows.filter(r => !['매출', '매출원가', '영업외수익', '영업외비용', '소득세등'].includes(categoryOf(r))).map(r => categoryOf(r))), preferredOpexCats);
  const adAccounts = ordered(uniq(rows.filter(r => categoryOf(r) === '광고선전비').map(r => r.account)), preferredAdAccounts);
  const feeAccounts = ordered(uniq(rows.filter(r => categoryOf(r) === '지급수수료').map(r => r.account)), preferredFeeAccounts);
  const out = [];

  out.push({ subject:'1. 매출액', label:'', rowClass:'row-section', value:(rs,col)=>metric(rs,col,'sales') });
  out.push({ subject:'', label:'상품매출', level:1, value:(rs,col)=>sumBy(rs,col,r=>categoryOf(r)==='매출') });
  salesChannels.forEach(([raw, label]) => out.push({ subject:'', label, level:2, alignRight:true, value:(rs,col)=>sumBy(rs,col,r=>categoryOf(r)==='매출' && r.memo===raw) }));

  out.push({ subject:'2. 매출원가', label:'', rowClass:'row-section', value:(rs,col)=>metric(rs,col,'cogs') });
  cogsAccounts.forEach(acc => out.push({ subject:'', label:acc, level:1, value:(rs,col)=>sumBy(rs,col,r=>categoryOf(r)==='매출원가' && r.account===acc) }));

  out.push({ subject:'3. 매출총이익', label:'', rowClass:'row-calc', value:(rs,col)=>metric(rs,col,'gp') });

  out.push({ subject:'4. 판매 및 관리비', label:'', rowClass:'row-section', flag:true, value:(rs,col)=>metric(rs,col,'opex') });
  opexCats.forEach(cat => {
    const needsFlag = ['급여', '복리후생비', '여비교통비', '세금과공과', '지급임차료', '운송비', '광고선전비', '지급수수료'].includes(cat);
    out.push({ subject:'', label:cat, level:1, flag:needsFlag, value:(rs,col)=>sumBy(rs,col,r=>categoryOf(r)===cat) });
    if (cat === '광고선전비') {
      adAccounts.forEach(acc => {
        const extra = ['Performance', 'SEO', 'Viral', 'VIRAL', 'Mass Media', '옥외광고'].includes(acc) ? '(전사)' : '';
        out.push({ subject:'', label:`${acc}${extra}`, level:2, alignRight:true, value:(rs,col)=>sumBy(rs,col,r=>categoryOf(r)==='광고선전비' && r.account===acc) });
      });
    }
    if (cat === '지급수수료') {
      const feePlatformDefs = [
        ['플랫폼 수수료(스마트스토어)', /smartstore|스마트스토어/i],
        ['플랫폼 수수료(쿠팡)', /coupang|쿠팡/i],
        ['플랫폼 수수료(오늘의집)', /today|오늘의집/i],
        ['플랫폼 수수료(자사몰)', /cafe24|자사몰/i],
        ['플랫폼 수수료(리씽크)', /re\-?think|리씽크/i],
        ['플랫폼 수수료(신세계)', /ssg|신세계/i],
        ['플랫폼 수수료(카카오쇼핑)', /kakao|카카오/i],
        ['플랫폼 수수료(펫박람회)', /pet\s?fair|펫박람회/i],
        ['플랫폼 수수료(펫바자)', /pet\s?bazaar|펫바자/i]
      ];
      feePlatformDefs.forEach(([label, re]) => out.push({ subject:'', label, level:2, alignRight:true, value:(rs,col)=>sumBy(rs,col,r=>categoryOf(r)==='지급수수료' && r.account==='플랫폼 수수료' && re.test(r.memo)) }));

      out.push({ subject:'', label:'공구 수수료', level:2, alignRight:true, value:(rs,col)=>sumBy(rs,col,r=>categoryOf(r)==='지급수수료' && isJointPurchaseFee(r)) });
      out.push({ subject:'', label:'외주비', level:2, alignRight:true, value:(rs,col)=>sumBy(rs,col,r=>categoryOf(r)==='지급수수료' && isOutsourceFee(r)) });
      out.push({ subject:'', label:'보관료', level:2, alignRight:true, value:(rs,col)=>sumBy(rs,col,r=>categoryOf(r)==='지급수수료' && isStorageFee(r)) });

      const excludedSubFeeAccounts = ['플랫폼 수수료', '공구 수수료', '공구수수료', '외주비', '용역비', '보관료'];
      feeAccounts
        .filter(acc => !excludedSubFeeAccounts.includes(acc))
        .forEach(acc => out.push({ subject:'', label:acc, level:2, alignRight:true, value:(rs,col)=>sumBy(rs,col,r=>categoryOf(r)==='지급수수료' && r.account===acc && !isJointPurchaseFee(r) && !isOutsourceFee(r) && !isStorageFee(r)) }));
    }
  });

  out.push({ subject:'5. 영업이익', label:'', rowClass:'row-calc', value:(rs,col)=>metric(rs,col,'op') });
  out.push({ subject:'6. 영업외수익', label:'', rowClass:'row-section', value:(rs,col)=>metric(rs,col,'nonIncome') });
  out.push({ subject:'7. 영업외비용', label:'', rowClass:'row-section', value:(rs,col)=>metric(rs,col,'nonExpense') });
  out.push({ subject:'8. 소득세차감전이익', label:'', rowClass:'row-calc', value:(rs,col)=>metric(rs,col,'preTax') });
  out.push({ subject:'9. 소득세등', label:'', rowClass:'row-section', flag:true, value:(rs,col)=>metric(rs,col,'tax') });
  taxAccounts.forEach(acc => out.push({ subject:'', label:acc, level:1, alignRight:true, value:(rs,col)=>sumBy(rs,col,r=>categoryOf(r)==='소득세등' && text(r.account).includes(acc)) }));
  out.push({ subject:'10. 당기순이익', label:'', rowClass:'row-calc', value:(rs,col)=>metric(rs,col,'net') });

  return out;
}

function renderControls() {
  const months = uniq(state.rows.map(r => r.month)).sort();
  const years = uniq(months.map(m => m.split('-')[0])).sort();

  const yearSelect = $('#yearSelect');
  const previousYear = yearSelect ? yearSelect.value : '';
  if (yearSelect) {
    if (!years.length) {
      yearSelect.innerHTML = '<option value="">-</option>';
      yearSelect.value = '';
      state.forceLatestMonth = false;
    } else {
      yearSelect.innerHTML = years.map(y => `<option value="${y}">${y}년</option>`).join('');
      const latestYear = years[years.length - 1];
      if (state.forceLatestMonth || !years.includes(previousYear)) {
        yearSelect.value = latestYear;
      } else {
        yearSelect.value = previousYear;
      }
    }
  }

  const monthSelect = $('#monthSelect');
  const selectedYear = currentYear();
  const previousMonth = monthSelect ? monthSelect.value : '';
  const monthsForYear = months
    .filter(m => m.startsWith(selectedYear + '-'))
    .map(m => m.split('-')[1]);

  if (monthSelect) {
    if (!selectedYear || !monthsForYear.length) {
      monthSelect.innerHTML = '<option value="">-</option>';
      monthSelect.value = '';
    } else {
      monthSelect.innerHTML =
        '<option value="__ALL__">전체</option>' +
        monthsForYear.map(m => `<option value="${m}">${Number(m)}월</option>`).join('');
      const latestMonth = monthsForYear[monthsForYear.length - 1];
      if (state.forceLatestMonth || !monthsForYear.includes(previousMonth)) {
        monthSelect.value = latestMonth;
      } else {
        monthSelect.value = previousMonth;
      }
    }
  }
  state.forceLatestMonth = false;

  const businesses = uniq(state.rows.map(r => effectiveBusiness(r))).sort((a, b) => a.localeCompare(b, 'ko'));
  const bizSelect = $('#businessSelect');
  const previousBiz = bizSelect.value || '__ALL__';
  bizSelect.innerHTML = `<option value="__ALL__">전체</option>` + businesses.map(b => `<option value="${b}">${b}</option>`).join('');
  bizSelect.value = businesses.includes(previousBiz) ? previousBiz : '__ALL__';

  const brandSelect = $('#brandSelect');
  if (brandSelect) {
    const selectedBiz = bizSelect.value;
    const previousBrand = brandSelect.value || '__ALL__';
    const brandPool = state.rows.filter(r => selectedBiz === '__ALL__' || effectiveBusiness(r) === selectedBiz);
    const brands = uniq(brandPool.map(r => effectiveBrand(r))).sort((a, b) => a.localeCompare(b, 'ko'));
    brandSelect.innerHTML = `<option value="__ALL__">전체</option>` + brands.map(b => `<option value="${b}">${b}</option>`).join('');
    brandSelect.value = brands.includes(previousBrand) ? previousBrand : '__ALL__';
  }

  renderRawFilterOptions();
}

function renderFileInfo(filteredRows) {
  const months = uniq(state.rows.map(r => r.month)).sort();
  const period = months.length ? `${months[0]} ~ ${months[months.length - 1]}` : '-';
  $('#fileInfo').innerHTML = `
    <div class="fileInfoCard">
      <div class="k">현재 첨부 파일</div>
      <div class="v" title="${escapeHtml(state.fileName || '첨부 파일 없음')}">${escapeHtml(state.fileName || '첨부 파일 없음')}</div>
    </div>
    <div class="fileInfoCard">
      <div class="k">불러온 데이터</div>
      <div class="v">${state.rows.length.toLocaleString('ko-KR')}행</div>
    </div>
    <div class="fileInfoCard">
      <div class="k">${currentPeriodType() === 'yearly' ? '선택연도 데이터' : '선택월 데이터'}</div>
      <div class="v">${filteredRows.length.toLocaleString('ko-KR')}행</div>
    </div>`;
}

function renderStatus(filteredRows, cols) {
  const months = uniq(state.rows.map(r => r.month)).sort();
  $('#sourceBadge').textContent = state.fileName ? '엑셀 데이터 반영됨' : '첨부 파일 없음';
  const statusDot = document.querySelector('.status-dot');
  if (statusDot) statusDot.classList.toggle('is-missing', !state.fileName);
  $('#statusBar').innerHTML = `
    <span><b>파일</b> ${state.fileName || '첨부 파일 없음'}</span>
    <span><b>전체 행</b> ${state.rows.length.toLocaleString('ko-KR')}개</span>
    <span><b>선택월 행</b> ${filteredRows.length.toLocaleString('ko-KR')}개</span>
    <span><b>기간</b> ${months[0] || '-'} ~ ${months[months.length - 1] || '-'}</span>
    <span><b>브랜드 컬럼</b> ${cols.length}개</span>
    <span><b>브랜드 필터</b> ${currentBrand() === '__ALL__' ? '전체' : currentBrand()}</span>`;
}

function buildKpiCardData(rows, prefixText) {
  const sales = metric(rows, null, 'sales');
  const gp = metric(rows, null, 'gp');
  const opex = metric(rows, null, 'opex');
  const op = metric(rows, null, 'op');
  const net = metric(rows, null, 'net');
  return [
    ['매출액', fmt(sales), `${prefixText} 순매출 합계`],
    ['매출총이익', fmt(gp), `${prefixText} GPM ${fmtPct(sales ? gp / sales : NaN)}`],
    ['판매 및 관리비', fmt(opex), `${prefixText} 매출 대비 ${fmtPct(sales ? opex / sales : NaN)}`],
    ['영업이익', fmt(op), `${prefixText} OPM ${fmtPct(sales ? op / sales : NaN)}`],
    ['당기순이익', fmt(net), `${prefixText} NPM ${fmtPct(sales ? net / sales : NaN)}`]
  ];
}

function renderKpiGroup(title, rows, prefixText, extraClass = '') {
  const cards = buildKpiCardData(rows, prefixText);
  const className = ['kpiGroup', extraClass].filter(Boolean).join(' ');
  return `
    <div class="${className}">
      <div class="kpiGroupTitle">${escapeHtml(title)}</div>
      <div class="kpiRow">
        ${cards.map(([label, value, sub]) => `<div class="card"><div class="label">${label}</div><div class="value">${value}</div><div class="sub">${sub}</div></div>`).join('')}
      </div>
    </div>`;
}

function renderCards(monthlyRows) {
  const years = availableYearsForCurrentFilter();
  const annualGroups = years.map(year => {
    const title = year === '2025' ? '2025년 총계' : `${year}년 누적`;
    const extraClass = year === '2025' ? 'historical' : '';
    return renderKpiGroup(title, rowsByYear(year), `${year}년`, extraClass);
  }).join('');
  const monthlyTitle = currentMonth() ? `${monthLabel(currentMonth())} 선택월` : '선택월';
  const monthlyGroup = renderKpiGroup(monthlyTitle, monthlyRows, '선택월');
  $('#kpiCards').innerHTML = annualGroups + monthlyGroup;
}

function getRawValue(row, key) {
  const values = {
    year: row.month ? row.month.split('-')[0] : '',
    month: row.month ? row.month.split('-')[1] : '',
    day: row.date ? row.date.slice(8, 10) : '',
    date: row.date || '',
    business: effectiveBusiness(row),
    brand: effectiveBrand(row),
    memo: row.memo || '',
    account: row.account || '',
    category: categoryOf(row),
    payment: toNum(row.payment),
    refund: toNum(row.refund),
    sales: toNum(row.sales),
    cost: toNum(row.cost),
    note: row.note || ''
  };
  return values[key] ?? '';
}

function rawRowSearchText(row) {
  return [
    getRawValue(row, 'date'),
    getRawValue(row, 'business'),
    getRawValue(row, 'brand'),
    getRawValue(row, 'memo'),
    getRawValue(row, 'account'),
    getRawValue(row, 'category'),
    getRawValue(row, 'payment'),
    getRawValue(row, 'refund'),
    getRawValue(row, 'sales'),
    getRawValue(row, 'cost'),
    getRawValue(row, 'note')
  ].map(v => text(v)).join(' ').toLowerCase();
}

function sortRawRows(rows) {
  const { key, direction } = rawSortState;
  const dir = direction === 'desc' ? -1 : 1;
  const numericKeys = new Set(['payment', 'refund', 'sales', 'cost']);

  return [...rows].sort((a, b) => {
    const av = getRawValue(a, key);
    const bv = getRawValue(b, key);

    if (numericKeys.has(key)) {
      return ((Number(av) || 0) - (Number(bv) || 0)) * dir;
    }

    return text(av).localeCompare(text(bv), 'ko', { numeric: true }) * dir;
  });
}

function setFilterOptions(selectId, values, allLabel, formatter = v => v) {
  const el = $(selectId);
  if (!el) return;
  const prev = el.value || '__ALL__';
  const options = ['__ALL__', ...values];
  el.innerHTML = options.map(v => `<option value="${escapeHtml(v)}">${v === '__ALL__' ? allLabel : escapeHtml(formatter(v))}</option>`).join('');
  el.value = options.includes(prev) ? prev : '__ALL__';
}

function renderRawFilterOptions() {
  const rows = state.rows || [];
  const years = uniq(rows.map(r => getRawValue(r, 'year'))).sort();
  const months = uniq(rows.map(r => getRawValue(r, 'month'))).sort();
  const days = uniq(rows.map(r => getRawValue(r, 'day'))).sort();
  const businesses = uniq(rows.map(r => getRawValue(r, 'business'))).sort((a,b)=>a.localeCompare(b,'ko'));
  const brands = uniq(rows.map(r => getRawValue(r, 'brand'))).sort((a,b)=>a.localeCompare(b,'ko'));
  const accounts = uniq(rows.map(r => getRawValue(r, 'account'))).sort((a,b)=>a.localeCompare(b,'ko'));
  const categories = uniq(rows.map(r => getRawValue(r, 'category'))).sort((a,b)=>a.localeCompare(b,'ko'));

  setFilterOptions('#rawYearFilter', years, '연도 전체', v => `${v}년`);
  setFilterOptions('#rawMonthFilter', months, '월 전체', v => `${Number(v)}월`);
  setFilterOptions('#rawDayFilter', days, '일자 전체', v => `${Number(v)}일`);
  setFilterOptions('#rawBusinessFilter', businesses, '사업부 전체');
  setFilterOptions('#rawBrandFilter', brands, '브랜드 전체');
  setFilterOptions('#rawAccountFilter', accounts, '계정과목 전체');
  setFilterOptions('#rawCategoryFilter', categories, '대분류 전체');
}

function getRawFilters() {
  return {
    year: $('#rawYearFilter')?.value || '__ALL__',
    month: $('#rawMonthFilter')?.value || '__ALL__',
    day: $('#rawDayFilter')?.value || '__ALL__',
    business: $('#rawBusinessFilter')?.value || '__ALL__',
    brand: $('#rawBrandFilter')?.value || '__ALL__',
    account: $('#rawAccountFilter')?.value || '__ALL__',
    category: $('#rawCategoryFilter')?.value || '__ALL__',
    keyword: text($('#rawKeywordInput')?.value || '').toLowerCase()
  };
}

function filterRawRows(rows) {
  const f = getRawFilters();
  return rows.filter(r =>
    (f.year === '__ALL__' || getRawValue(r, 'year') === f.year) &&
    (f.month === '__ALL__' || getRawValue(r, 'month') === f.month) &&
    (f.day === '__ALL__' || getRawValue(r, 'day') === f.day) &&
    (f.business === '__ALL__' || getRawValue(r, 'business') === f.business) &&
    (f.brand === '__ALL__' || getRawValue(r, 'brand') === f.brand) &&
    (f.account === '__ALL__' || getRawValue(r, 'account') === f.account) &&
    (f.category === '__ALL__' || getRawValue(r, 'category') === f.category) &&
    (!f.keyword || rawRowSearchText(r).includes(f.keyword))
  );
}

function getCurrentRawRows() {
  return sortRawRows(filterRawRows(state.rows || []));
}

function exportRawDataToExcel() {
  if (typeof XLSX === 'undefined') {
    alert('엑셀 다운로드 기능을 불러오지 못했습니다. 인터넷 연결 후 다시 시도해 주세요.');
    return;
  }

  const rows = getCurrentRawRows();
  if (!rows.length) {
    alert('다운로드할 Raw data가 없습니다.');
    return;
  }

  const exportRows = rows.map(r => ({
    '거래일자': getRawValue(r, 'date'),
    '사업부': getRawValue(r, 'business'),
    '브랜드': getRawValue(r, 'brand'),
    '내용': getRawValue(r, 'memo'),
    '계정과목': getRawValue(r, 'account'),
    '대분류': getRawValue(r, 'category'),
    '결제금액': getRawValue(r, 'payment'),
    '환불액': getRawValue(r, 'refund'),
    '순매출': getRawValue(r, 'sales'),
    '비용': getRawValue(r, 'cost'),
    '비고': getRawValue(r, 'note')
  }));

  const ws = XLSX.utils.json_to_sheet(exportRows);
  ws['!cols'] = [
    { wch: 12 }, { wch: 14 }, { wch: 14 }, { wch: 34 }, { wch: 18 },
    { wch: 16 }, { wch: 14 }, { wch: 14 }, { wch: 14 }, { wch: 14 }, { wch: 28 }
  ];

  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Raw data');

  const year = currentYear() || '전체연도';
  const month = currentMonthOnly();
  const monthPart = month && month !== '__ALL__' ? `${month}월` : '전체월';
  const dateStamp = new Date().toISOString().slice(0, 10).replace(/-/g, '');
  XLSX.writeFile(wb, `FB_Global_Raw_Data_${year}_${monthPart}_${dateStamp}.xlsx`);
}

function renderRawData() {
  const container = $('#rawDataTable');
  const countEl = $('#rawCount');
  if (!container) return;

  renderRawFilterOptions();

  const allRows = state.rows || [];
  const rows = getCurrentRawRows();

  if (countEl) {
    countEl.textContent = rows.length === allRows.length
      ? `${allRows.length.toLocaleString('ko-KR')}행`
      : `${rows.length.toLocaleString('ko-KR')} / ${allRows.length.toLocaleString('ko-KR')}행`;
  }

  if (!allRows.length) {
    container.innerHTML = '<div class="empty">첨부된 raw data가 없습니다. 엑셀 파일을 업로드해 주세요.</div>';
    return;
  }

  if (!rows.length) {
    container.innerHTML = '<div class="empty">선택한 조건에 해당하는 Raw data가 없습니다.</div>';
    return;
  }

  const headers = [
    { key:'date', label:'거래일자' },
    { key:'business', label:'사업부' },
    { key:'brand', label:'브랜드' },
    { key:'memo', label:'내용' },
    { key:'account', label:'계정과목' },
    { key:'category', label:'대분류' },
    { key:'payment', label:'결제금액', numeric:true },
    { key:'refund', label:'환불액', numeric:true },
    { key:'sales', label:'순매출', numeric:true },
    { key:'cost', label:'비용', numeric:true },
    { key:'note', label:'비고' }
  ];

  const sortMark = key => rawSortState.key === key ? (rawSortState.direction === 'asc' ? '▲' : '▼') : '↕';

  const body = rows.map(r => `
    <tr>
      <td>${escapeHtml(getRawValue(r, 'date'))}</td>
      <td>${escapeHtml(getRawValue(r, 'business'))}</td>
      <td>${escapeHtml(getRawValue(r, 'brand'))}</td>
      <td>${escapeHtml(getRawValue(r, 'memo'))}</td>
      <td>${escapeHtml(getRawValue(r, 'account'))}</td>
      <td>${escapeHtml(getRawValue(r, 'category'))}</td>
      <td class="num">${fmt(getRawValue(r, 'payment'))}</td>
      <td class="num">${fmt(getRawValue(r, 'refund'))}</td>
      <td class="num">${fmt(getRawValue(r, 'sales'))}</td>
      <td class="num">${fmt(getRawValue(r, 'cost'))}</td>
      <td>${escapeHtml(getRawValue(r, 'note'))}</td>
    </tr>`).join('');

  container.innerHTML = `
    <table class="rawTable">
      <thead><tr>${headers.map(h => `<th data-key="${h.key}">${h.label}<span class="sortMark">${sortMark(h.key)}</span></th>`).join('')}</tr></thead>
      <tbody>${body}</tbody>
    </table>`;

  container.querySelectorAll('th[data-key]').forEach(th => {
    th.addEventListener('click', () => {
      const key = th.dataset.key;
      if (rawSortState.key === key) {
        rawSortState.direction = rawSortState.direction === 'asc' ? 'desc' : 'asc';
      } else {
        rawSortState.key = key;
        rawSortState.direction = 'asc';
      }
      renderRawData();
    });
  });
}

function escapeHtml(s) {
  return text(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function renderStatement() {
  const rows = statementRows();
  const cols = getColumns(rows);
  renderFileInfo(rows);
  renderStatus(rows, cols);
  renderCards(rows);
  $('#monthStamp').textContent = statementLabel();

  if (!rows.length) {
    $('#statement').innerHTML = '<div class="empty">첨부된 엑셀 파일이 없습니다. 엑셀 파일을 업로드해 주세요.</div>';
    renderRawData();
    return;
  }

  const bizGroups = [];
  cols.forEach(c => {
    const last = bizGroups[bizGroups.length - 1];
    if (last && last.business === c.business) last.items.push(c);
    else bizGroups.push({ business: c.business, items: [c] });
  });

  const rowDefs = buildRows(rows);
  const dynamicWidth = 118;

  let html = `<table class="pnl"><colgroup><col style="width:120px"><col style="width:165px">${cols.map(() => `<col style="width:${dynamicWidth}px">`).join('')}<col style="width:120px"></colgroup>`;
  html += '<thead>';
  html += '<tr><th colspan="2" rowspan="2">과&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;목</th>' + bizGroups.map(g => `<th colspan="${g.items.length}">${escapeHtml(g.business)}</th>`).join('') + '<th rowspan="2" class="totalCol">합계금액</th></tr>';
  html += '<tr>' + cols.map(c => `<th>${escapeHtml(c.brand)}</th>`).join('') + '</tr>';
  html += '</thead><tbody>';

  rowDefs.forEach(def => {
    const rowClass = [def.rowClass || '', def.subject ? 'numbered-row' : ''].filter(Boolean).join(' ');
    const subjectClass = def.flag ? 'subject flag' : 'subject';
    const itemClass = def.level === 2 ? 'item item-l2' : def.level === 3 ? 'item item-l3' : def.level === 1 ? 'item item-l1' : 'item';
    const emphClass = def.emph ? ' emph' : '';
    const alignClass = def.alignRight ? ' item-right' : '';
    html += `<tr class="${rowClass}"><td class="${subjectClass}">${escapeHtml(def.subject || '')}</td><td class="${itemClass + emphClass + alignClass}">${escapeHtml(def.label || '')}</td>`;
    cols.forEach(col => {
      const value = def.value(rows, col);
      html += `<td class="num">${fmt(value)}</td>`;
    });
    html += `<td class="num totalCol">${fmt(def.value(rows, null))}</td></tr>`;
  });

  html += '</tbody></table>';
  $('#statement').innerHTML = html;
  renderRawData();
}

function normalizeHeaderName(v) {
  return norm(v).replace(/[()]/g, '');
}

function findCol(header, aliases) {
  const normalized = header.map(normalizeHeaderName);
  for (const alias of aliases) {
    const needle = normalizeHeaderName(alias);
    const idx = normalized.findIndex(h => h === needle || h.includes(needle));
    if (idx >= 0) return idx;
  }
  return -1;
}

function parseWorkbookRows(arrayBuffer, fileName) {
  if (typeof XLSX === 'undefined') throw new Error('엑셀 파서 로딩에 실패했습니다. 인터넷 연결 후 다시 열어주세요.');
  const wb = XLSX.read(arrayBuffer, { type: 'array', cellDates: false });
  const sheet = wb.Sheets[wb.SheetNames[0]];
  const matrix = XLSX.utils.sheet_to_json(sheet, { header: 1, raw: true, defval: '' });

  let headerIndex = -1;
  for (let i = 0; i < Math.min(matrix.length, 80); i++) {
    const joined = matrix[i].map(text).join('|');
    if (joined.includes('거래일자') && joined.includes('사업부') && joined.includes('브랜드') && joined.includes('계정과목')) {
      headerIndex = i;
      break;
    }
  }
  if (headerIndex < 0) throw new Error('헤더 행을 찾지 못했습니다. 거래일자/사업부/브랜드/계정과목 컬럼명이 필요합니다.');

  const header = matrix[headerIndex];
  const idx = {
    date: findCol(header, ['거래일자', '거래일']),
    business: findCol(header, ['사업부']),
    brand: findCol(header, ['브랜드']),
    payment: findCol(header, ['결제금액']),
    refund: findCol(header, ['환불액']),
    sales: findCol(header, ['순매출', '매출액']),
    cost: findCol(header, ['비용', '지출금액']),
    memo: findCol(header, ['내용', '거래내용', '적요']),
    account: findCol(header, ['계정과목']),
    category: findCol(header, ['대분류', '분류']),
    note: findCol(header, ['비고', '메모'])
  };

  const required = ['date', 'business', 'brand', 'account', 'category'];
  const missing = required.filter(k => idx[k] < 0);
  if (missing.length) throw new Error('필수 컬럼 누락: ' + missing.join(', '));

  const parsed = [];
  for (let r = headerIndex + 1; r < matrix.length; r++) {
    const row = matrix[r] || [];
    const month = monthOf(row[idx.date]);
    const business = text(row[idx.business]);
    const brand = text(row[idx.brand]);
    const account = text(row[idx.account]);
    const category = text(row[idx.category]);
    if (!month || (!business && !brand && !account && !category)) continue;
    parsed.push({
      sourceRow: r + 1,
      date: parseAnyDate(row[idx.date])?.toISOString().slice(0, 10) || '',
      month,
      business,
      brand,
      payment: idx.payment >= 0 ? toNum(row[idx.payment]) : 0,
      refund: idx.refund >= 0 ? toNum(row[idx.refund]) : 0,
      sales: idx.sales >= 0 ? toNum(row[idx.sales]) : 0,
      cost: idx.cost >= 0 ? toNum(row[idx.cost]) : 0,
      memo: idx.memo >= 0 ? text(row[idx.memo]) : '',
      account,
      category,
      note: idx.note >= 0 ? text(row[idx.note]) : ''
    });
  }

  if (!parsed.length) throw new Error('읽어온 데이터 행이 없습니다.');
  state.rows = parsed;
  state.fileName = fileName;
  state.forceLatestMonth = true;
  saveDashboardState();
  renderControls();
  renderStatement();
}

$('#fileInput').addEventListener('change', async e => {
  const file = e.target.files?.[0];
  if (!file) return;
  try {
    const buf = await file.arrayBuffer();
    parseWorkbookRows(buf, file.name);
  } catch (err) {
    alert(err.message || String(err));
  }
});

